mapper.select:
SELECT ph.tier_promotion_id AS tierPromotionId, ph.employee_id AS employeeId, e.employee_name AS employeeName, tc_cur.tier_config_tier AS currentTier, tc_tgt.tier_config_tier AS targetTier, ph.tier_accumulated_point AS tierAccumulatedPoint, tc_tgt.tier_config_promotion_point AS targetPromotionPoint, ph.tier_promo_status AS tierPromoStatus, ph.created_at AS createdAt FROM promotion_history ph JOIN employee e ON e.employee_id = ph.employee_id JOIN tier_config tc_cur ON tc_cur.tier_config_id = ph.current_tier_config_id JOIN tier_config tc_tgt ON tc_tgt.tier_config_id = ph.target_tier_config_id
AND tc_tgt.tier_config_tier = #{targetTier}
ORDER BY ph.created_at DESC LIMIT #{size} OFFSET #{offset}
